import React from "react";

import UserItem from './UserItem';
import './UsersList.css';

const UsersList = props => {
    const users = props.item || [];  // default empty array if undefined

    if (users.length === 0) {
        return (
          <div className="center">
            <card>
              <h2>No User found.</h2>
            </card>
          </div>
        );
    }

    return (
      <ul>
        {users.map(user => (
          <UserItem 
            key={user.id} 
            id={user.id} 
            image={user.image} 
            name={user.name}  
            placeCount={user.places.length}
          />
        ))}
      </ul>
    );
};

export default UsersList;
